mapper.update:
UPDATE DDD_CARE
SET care_title = #{careTitle}, care_post = #{carePost}, care_date = #{careDate}, care_recruit = #{careRecruit}
WHERE care_number = #{careNumber} AND user_number = #{userNumber}

UPDATE DDD_CARE
SET care_status = 'deleted'
WHERE care_number = #{careNumber} AND user_number = #{userNumber}

UPDATE DDD_CARE c
SET c.care_status = 'open'
WHERE c.care_number = #{careNumber}
AND (SELECT COUNT(*) FROM ddd_care_apply a WHERE a.care_number = c.care_number) < c.care_recruit;

mapper.select:
SELECT COUNT(a.apply_number) || '/' || c.care_recruit AS apply_status
FROM ddd_care c
LEFT JOIN ddd_care_apply a ON c.care_number = a.care_number
WHERE c.care_number = #{careNumber}
GROUP BY c.care_recruit;
